// NODE: Parse Video Pipeline Message
// Routes incoming Telegram messages to the correct handler:
//   - #body scenario_name clip_index [section]  → body clip upload
//   - #hook scenario_name                       → manual hook clip upload
//   - #outro scenario_name label                → manual outro clip upload
//   - /produce scenario_name [template]         → trigger video production
//   - /done                                     → finish recording, start production
//   - video with no caption (during recording)  → auto body clip
//   - anything else                             → ignored
// Mode: Run Once for All Items
//
// WIRING: Telegram Trigger (message) → this Code node → Switch node (Route Message)
// Switch outputs: body_clip | hook_clip | outro_clip | produce | done_recording | auto_body_clip | unknown

const update = $input.first().json;
const message = update.message || update;
const text = (message.caption || message.text || '').trim();
const chatId = message.chat?.id || '';

const hasVideo = !!(message.video || message.document);
const video = message.video || message.document || {};

// ─── #body scenario_name clip_index [section] ───
const bodyMatch = text.match(/#body\s+(\S+)\s+(\d+)(?:\s+(\S+))?/i);
if (hasVideo && bodyMatch) {
  return [{
    json: {
      messageType: 'body_clip',
      scenarioName: bodyMatch[1],
      clipIndex: parseInt(bodyMatch[2], 10),
      section: bodyMatch[3] || '',
      fileId: video.file_id,
      fileSize: video.file_size || 0,
      duration: video.duration || 0,
      chatId,
    }
  }];
}

// ─── #hook scenario_name ───
const hookMatch = text.match(/#hook\s+(\S+)/i);
if (hasVideo && hookMatch) {
  return [{
    json: {
      messageType: 'hook_clip',
      scenarioName: hookMatch[1],
      fileId: video.file_id,
      fileSize: video.file_size || 0,
      duration: video.duration || 0,
      chatId,
    }
  }];
}

// ─── #outro scenario_name label ───
const outroMatch = text.match(/#outro\s+(\S+)\s+(\S+)/i);
if (hasVideo && outroMatch) {
  return [{
    json: {
      messageType: 'outro_clip',
      scenarioName: outroMatch[1],
      label: outroMatch[2],
      fileId: video.file_id,
      fileSize: video.file_size || 0,
      duration: video.duration || 0,
      chatId,
    }
  }];
}

// ─── /produce [scenario_name] — no args = next ready scenario ───
const produceMatch = text.match(/^\/produce(?:\s+(\S+))?$/i);
if (produceMatch) {
  return [{
    json: {
      messageType: 'produce',
      scenarioName: produceMatch[1] || '',
      chatId,
    }
  }];
}

// ─── Access workflow static data (shared recording state) ───
const staticData = $getWorkflowStaticData('global');

// ─── /done — finish recording ───
if (text.match(/^\/done$/i)) {
  const activeRec = staticData.activeRecording;
  return [{
    json: {
      messageType: 'done_recording',
      scenarioName: activeRec ? activeRec.scenarioName : '',
      chatId,
    }
  }];
}

// ─── Video with no recognized command during active recording → auto body clip ───
if (hasVideo && staticData.activeRecording) {
  return [{
    json: {
      messageType: 'auto_body_clip',
      fileId: video.file_id,
      fileSize: video.file_size || 0,
      duration: video.duration || 0,
      chatId,
    }
  }];
}

// Unknown — ignore silently
return [{
  json: {
    messageType: 'unknown',
    text: text.substring(0, 100),
    chatId,
  }
}];

// NODE: Save Clip (unified handler for body/hook/outro)
// Prepares the Airtable record for any clip type uploaded via Telegram
// Mode: Run Once for All Items
//
// WIRING: Parse Message → Route Message (Switch) → Find Scenario → this Code node → Airtable Create → Telegram confirm
//
// Input: parsed message data from Parse Message + scenario record from Find Scenario
// Handles all 3 clip types: body_clip, hook_clip, outro_clip

const parsed = $('Parse Message').first().json;
const scenario = $('Find Scenario (Clip)').first().json;

if (!scenario || !scenario.id) {
  return [{
    json: {
      error: true,
      chatId: parsed.chatId,
      message: 'Scenario "' + parsed.scenarioName + '" not found in Airtable'
    }
  }];
}

const messageType = parsed.messageType;

// Build the Airtable record fields based on clip type
const record = {
  scenario_id: [scenario.id],
  telegram_file_id: parsed.fileId,
  clip_duration_sec: parsed.duration,
  status: 'uploaded',
};

if (messageType === 'body_clip') {
  record.clip_name = parsed.scenarioName + '_body_' + parsed.clipIndex;
  record.clip_type = 'body';
  record.clip_index = parsed.clipIndex;
  record.section = parsed.section || '';  // optional template section mapping
} else if (messageType === 'hook_clip') {
  record.clip_name = parsed.scenarioName + '_hook';
  record.clip_type = 'hook_manual';
  record.clip_index = 0;
} else if (messageType === 'outro_clip') {
  record.clip_name = parsed.scenarioName + '_outro_' + parsed.label;
  record.clip_type = 'outro_manual';
  record.clip_index = 0;
  record.label = parsed.label || '';
}

// Build confirmation message
let confirmMsg = '';
if (messageType === 'body_clip') {
  confirmMsg = '\u2705 Body clip #' + parsed.clipIndex + ' saved for "' + parsed.scenarioName + '"';
  if (parsed.section) confirmMsg += ' (section: ' + parsed.section + ')';
} else if (messageType === 'hook_clip') {
  confirmMsg = '\u2705 Hook clip saved for "' + parsed.scenarioName + '"';
} else if (messageType === 'outro_clip') {
  confirmMsg = '\u2705 Outro clip "' + parsed.label + '" saved for "' + parsed.scenarioName + '"';
}

return [{
  json: {
    ...record,
    chatId: parsed.chatId,
    scenarioName: parsed.scenarioName,
    confirmMsg,
  }
}];

// NODE: Prepare Production (MVP — Concept 3: chat_screenshot)
// Consolidates scenario data + body clips into a production plan
// Mode: Run Once for All Items
//
// WIRING: Find Produce Clips (Airtable) → this Code node → Generate Hook
// References: $('Load Production Data'), $('Find Produce Scenario'), $input (body clips)

// Helper: "toxic-sad-happy-girl-1771197483216" → "Toxic Sad Happy Girl"
function formatName(raw) {
  if (!raw) return 'Scenario';
  return raw.replace(/-\d{10,}$/, '').split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
}

const chatId = $('Load Production Data').first().json.chatId;

// ─── Get scenario from Airtable search result ───
const scenarioItems = $('Find Produce Scenario').all().map(i => i.json);
if (scenarioItems.length === 0) {
  return [{
    json: {
      error: true,
      chatId,
      message: '⚠️ Nessuno scenario pronto (status=ready) trovato.',
    }
  }];
}

const scenario = scenarioItems[0];
const scenarioName = scenario.scenario_name;

// ─── Parse scenario JSON ───
let scenarioJson = scenario.scenario_json;
if (typeof scenarioJson === 'string') {
  try { scenarioJson = JSON.parse(scenarioJson); } catch(e) { scenarioJson = null; }
}

// ─── Parse copy JSON (contains VO scripts) ───
let copyJson = scenario.generated_copy_json;
if (typeof copyJson === 'string') {
  try { copyJson = JSON.parse(copyJson); } catch(e) { copyJson = null; }
}

// ─── Get body clips from input (Airtable search result) ───
const clipRecords = $input.all().map(i => i.json);

if (clipRecords.length === 0) {
  return [{
    json: {
      error: true,
      chatId,
      message: '⚠️ Nessuna body clip trovata per "' + formatName(scenarioName) + '". Registra prima le clip.',
    }
  }];
}

// ─── Hook type: chat_screenshot for Concept 3 MVP ───
const hookType = 'chat_screenshot';

// ─── Outro: skip for Concept 3 ───
const selectedOutro = { type: 'none' };

// ─── Standard body clip template ───
const template = {
  segments: [
    { section: 'hook', duration: 3.0 },
    { section: 'screenshot', duration: 1.0 },
    { section: 'upload_chat', duration: 1.0 },
    { section: 'toxic_score', duration: 3.0 },
    { section: 'soul_type', duration: 3.0 },
    { section: 'deep_dive', duration: 3.0 },
  ],
  totalDuration: 14.0,
};

// ─── Sort and map body clips ───
const bodyClips = clipRecords
  .filter(c => c.clip_type === 'body' || !c.clip_type)
  .sort((a, b) => (a.clip_index || 0) - (b.clip_index || 0))
  .map(clip => ({
    clipIndex: clip.clip_index,
    section: clip.section || 'body_' + clip.clip_index,
    fileId: clip.telegram_file_id,
    duration: clip.clip_duration_sec || 0,
    clipName: clip.clip_name,
  }));

// ─── Map clips to template body segments ───
const bodySegments = template.segments.filter(s => s.section !== 'hook' && s.section !== 'outro');
const clipMapping = bodySegments.map((seg, i) => {
  let clip = bodyClips.find(c => c.section === seg.section);
  if (!clip && i < bodyClips.length) clip = bodyClips[i];
  return {
    section: seg.section,
    targetDuration: seg.duration,
    fileId: clip ? clip.fileId : null,
    actualDuration: clip ? clip.duration : null,
  };
});

return [{
  json: {
    scenarioName,
    displayName: formatName(scenarioName),
    chatId,
    hookType,
    selectedOutro,
    scenarioJson,
    copyJson,
    template,
    bodyClips,
    clipMapping,
    scenarioRecordId: scenario.id,
    hookText: scenario.generated_hook_text || '',
  }
}];

// NODE: Generate Hook (Modular)
// Routes by hook type from concept config:
//   - chat_screenshot → Puppeteer screenshot of the chat conversation
//   - manual_clip → just passes through the already-uploaded hook clip file_id
//   - ai_image → kie.ai Nano Banana Pro (single image → img2vid later)
//   - ai_multi_image → kie.ai x3 images (before_after: girl+bf moments)
//
// For ai_image/ai_multi_image: uses environment frame + girl reference
// Mode: Run Once for All Items
//
// WIRING:
//   manual_clip path:  Prepare Production → this node → [hook ready]
//   ai_image path:     Prepare Production → Download First Body Clip → Extract Frame
//                      → AI Agent (Generate Hook Prompt) → this node → Telegram Approval
//   ai_multi_image:    same as ai_image but loops 3 times
//
// Input expects hookPrompt from $('Generate Hook Prompt') for AI modes

// ─── fetch polyfill (n8n Code node sandbox lacks global fetch) ───
const _https = require('https');
const _http = require('http');
const { URL } = require('url');
function fetch(url, opts = {}) {
  return new Promise((resolve, reject) => {
    const u = new URL(url);
    const lib = u.protocol === 'https:' ? _https : _http;
    const body = opts.body || null;
    const ro = {
      hostname: u.hostname,
      port: u.port || undefined,
      path: u.pathname + u.search,
      method: opts.method || 'GET',
      headers: { ...(opts.headers || {}) },
    };
    if (body) ro.headers['Content-Length'] = Buffer.byteLength(body);
    const req = lib.request(ro, res => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const buf = Buffer.concat(chunks);
        resolve({
          ok: res.statusCode >= 200 && res.statusCode < 300,
          status: res.statusCode,
          text: () => Promise.resolve(buf.toString()),
          json: () => Promise.resolve(JSON.parse(buf.toString())),
          arrayBuffer: () => Promise.resolve(buf.buffer.slice(buf.byteOffset, buf.byteOffset + buf.byteLength)),
        });
      });
    });
    req.on('error', reject);
    if (body) req.write(body);
    req.end();
  });
}

const KIE_API_KEY = '7670ade582cc72601f388dbdc0525b9e';
const KIE_API_URL = 'https://api.kie.ai/api/v1/jobs';
const SCREENSHOT_URL = 'http://host.docker.internal:3456/screenshot';
const MAX_RETRIES = 1;
const RETRY_DELAY_MS = 5000;

// ─── retry helper ───
async function withRetry(fn, label = 'API call') {
  for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
    try {
      return await fn();
    } catch (err) {
      if (attempt === MAX_RETRIES) throw err;
      // Wait before retry
      await new Promise(r => setTimeout(r, RETRY_DELAY_MS));
    }
  }
}

// ─── kie.ai helpers (inlined for n8n) ───
async function kieGenerate(prompt, imageRefs, options = {}) {
  const { aspectRatio = '9:16', resolution = '2K' } = options;
  const res = await fetch(KIE_API_URL + '/createTask', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': 'Bearer ' + KIE_API_KEY,
    },
    body: JSON.stringify({
      model: 'nano-banana-pro',
      input: { prompt, image_input: imageRefs, aspect_ratio: aspectRatio, resolution, output_format: 'png' },
    }),
  });
  if (!res.ok) throw new Error('kie.ai createTask: ' + res.status + ' ' + (await res.text()));
  const data = await res.json();
  if (data.code !== 200) throw new Error('kie.ai: ' + JSON.stringify(data));
  return data.data.taskId;
}

async function kiePoll(taskId, timeoutMs = 180000) {
  const start = Date.now();
  while (Date.now() - start < timeoutMs) {
    await new Promise(r => setTimeout(r, 3000));
    const res = await fetch(KIE_API_URL + '/recordInfo?taskId=' + taskId, {
      headers: { 'Authorization': 'Bearer ' + KIE_API_KEY },
    });
    if (!res.ok) continue;
    const data = await res.json();
    if (data.data?.state === 'success') {
      return JSON.parse(data.data.resultJson).resultUrls?.[0];
    }
    if (data.data?.state === 'fail') throw new Error(data.data.failMsg || 'failed');
  }
  throw new Error('Timeout after ' + (timeoutMs / 1000) + 's');
}
// ─── End helpers ───

const production = $('Prepare Production').first().json;
const hookType = production.hookType;
const chatId = production.chatId;
const scenarioName = production.scenarioName;

// ═══════════════════════════════════════
// MANUAL CLIP — already uploaded via #hook
// ═══════════════════════════════════════
if (hookType === 'manual_clip') {
  if (!production.hookClipFileId) {
    return [{ json: { error: true, chatId, message: '\u274C No hook clip uploaded. Send: #hook ' + scenarioName + ' + video' } }];
  }
  return [{
    json: {
      hookReady: true,
      hookSource: 'manual_clip',
      hookFileId: production.hookClipFileId,
      hookDuration: production.hookClipDuration,
      chatId,
      scenarioName,
    }
  }];
}

// ═══════════════════════════════════════
// AI IMAGE — single kie.ai generation
// ═══════════════════════════════════════
if (hookType === 'ai_image') {
  if (!KIE_API_KEY) {
    return [{ json: { error: true, chatId, message: 'kie.ai API key not configured' } }];
  }

  const hookPrompt = $('Generate Hook Prompt').first().json.text || '';
  if (!hookPrompt) {
    return [{ json: { error: true, chatId, message: 'No hook prompt from AI Agent' } }];
  }

  // Reference images: env frame + girl character
  const envFrameUrl = $input.first().json.envFrameUrl || '';
  const girlRefUrl = production.girlRefUrl || '';
  const imageRefs = [envFrameUrl, girlRefUrl].filter(Boolean);

  if (imageRefs.length === 0) {
    return [{ json: { error: true, chatId, message: 'No reference images (need env frame or girl ref)' } }];
  }

  try {
    const result = await withRetry(async () => {
      const taskId = await kieGenerate(hookPrompt, imageRefs);
      const imageUrl = await kiePoll(taskId);
      if (!imageUrl) throw new Error('kie.ai returned no image');
      return imageUrl;
    }, 'kie.ai hook');

    const imgRes = await fetch(result);
    const imgBuffer = Buffer.from(await imgRes.arrayBuffer());

    return [{
      json: {
        hookReady: false, // needs Telegram approval + img2vid
        hookSource: 'ai_image',
        hookImageUrl: result,
        chatId,
        scenarioName,
      },
      binary: {
        hookImage: {
          data: imgBuffer.toString('base64'),
          mimeType: 'image/png',
          fileName: 'hook_ai.png',
        }
      }
    }];
  } catch (err) {
    // Self-healing: AI hook failed after retry → fall back to placeholder
    return [{
      json: {
        hookReady: true,
        hookSource: 'fallback_blank',
        hookFailed: true,
        hookError: err.message,
        chatId,
        scenarioName,
        warning: '\u26A0\uFE0F Hook AI failed after retry: ' + err.message + '. Using blank placeholder.',
      }
    }];
  }
}

// ═══════════════════════════════════════
// AI MULTI IMAGE — 3 images for before_after
// ═══════════════════════════════════════
if (hookType === 'ai_multi_image') {
  if (!KIE_API_KEY) {
    return [{ json: { error: true, chatId, message: 'kie.ai API key not configured' } }];
  }

  // For multi-image, we expect 3 separate prompts from the AI Agent
  // The AI Agent should output: { prompt1, prompt2, prompt3 }
  const aiOutput = $('Generate Hook Prompt').first().json;
  const prompts = [
    aiOutput.prompt1 || aiOutput.text || '',
    aiOutput.prompt2 || '',
    aiOutput.prompt3 || '',
  ].filter(Boolean);

  if (prompts.length === 0) {
    return [{ json: { error: true, chatId, message: 'No hook prompts from AI Agent' } }];
  }

  const girlRefUrl = production.girlRefUrl || '';
  const imageRefs = girlRefUrl ? [girlRefUrl] : [];
  const generatedImages = [];

  try {
    for (let i = 0; i < prompts.length; i++) {
      const imageUrl = await withRetry(async () => {
        const taskId = await kieGenerate(prompts[i], imageRefs);
        const url = await kiePoll(taskId);
        if (!url) throw new Error('Image ' + (i + 1) + ' returned no URL');
        return url;
      }, 'kie.ai multi-hook #' + (i + 1));

      const imgRes = await fetch(imageUrl);
      const imgBuffer = Buffer.from(await imgRes.arrayBuffer());
      generatedImages.push({
        url: imageUrl,
        base64: imgBuffer.toString('base64'),
      });
    }

    // Return all images for Telegram approval (as a collage or sequential sends)
    const binaryData = {};
    generatedImages.forEach((img, i) => {
      binaryData['hookImage' + (i + 1)] = {
        data: img.base64,
        mimeType: 'image/png',
        fileName: 'hook_' + (i + 1) + '.png',
      };
    });

    return [{
      json: {
        hookReady: false,
        hookSource: 'ai_multi_image',
        hookImageUrls: generatedImages.map(i => i.url),
        imageCount: generatedImages.length,
        chatId,
        scenarioName,
      },
      binary: binaryData,
    }];
  } catch (err) {
    // Self-healing: multi-image failed → fall back to placeholder
    return [{
      json: {
        hookReady: true,
        hookSource: 'fallback_blank',
        hookFailed: true,
        hookError: err.message,
        chatId,
        scenarioName,
        warning: '\u26A0\uFE0F Multi-image hook failed after retry: ' + err.message + '. Using blank placeholder.',
      }
    }];
  }
}

// ═══════════════════════════════════════
// CHAT SCREENSHOT — Puppeteer screenshot of the chat conversation
// ═══════════════════════════════════════
if (hookType === 'chat_screenshot') {
  const scenarioJson = production.scenarioJson;
  if (!scenarioJson || !scenarioJson.chat) {
    return [{ json: { error: true, chatId, message: '\u274C No chat data in scenario for screenshot' } }];
  }

  try {
    const screenshotBuffer = await withRetry(async () => {
      const res = await fetch(SCREENSHOT_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(scenarioJson),
      });
      if (!res.ok) {
        const errText = await res.text();
        throw new Error('Screenshot server ' + res.status + ': ' + errText);
      }
      const buffer = Buffer.from(await res.arrayBuffer());
      if (buffer.length < 1000) throw new Error('Screenshot too small (' + buffer.length + ' bytes)');
      return buffer;
    }, 'Screenshot server');

    return [{
      json: {
        hookReady: true, // deterministic screenshot, no approval needed
        hookSource: 'chat_screenshot',
        chatId,
        scenarioName,
      },
      binary: {
        hookImage: {
          data: screenshotBuffer.toString('base64'),
          mimeType: 'image/png',
          fileName: 'hook_screenshot.png',
        }
      }
    }];
  } catch (err) {
    // Self-healing: screenshot server failed → fall back to blank placeholder
    return [{
      json: {
        hookReady: true,
        hookSource: 'fallback_blank',
        hookFailed: true,
        hookError: err.message,
        chatId,
        scenarioName,
        warning: '\u26A0\uFE0F Screenshot server failed: ' + err.message + '. Using blank placeholder.',
      }
    }];
  }
}

// Unknown hook type
return [{ json: { error: true, chatId, message: 'Unknown hook_type: ' + hookType } }];

// NODE: Generate Voiceover via Fish.audio
// Takes the VO script from the copy JSON (generated by Workflow 1) and converts to audio
// Copy JSON structure: { hookVO, bodyClips: [{ vo }], outroVO }
// Self-healing: retries 1x on failure, falls back to no-VO if still failing
// Mode: Run Once for All Items
//
// WIRING: Prepare Production → this Code node → Send VO to Telegram
// Input: production data with copyJson containing VO scripts

// ─── fetch polyfill (n8n Code node sandbox lacks global fetch) ───
const _https = require('https');
const _http = require('http');
const { URL } = require('url');
function fetch(url, opts = {}) {
  return new Promise((resolve, reject) => {
    const u = new URL(url);
    const lib = u.protocol === 'https:' ? _https : _http;
    const body = opts.body || null;
    const ro = {
      hostname: u.hostname,
      port: u.port || undefined,
      path: u.pathname + u.search,
      method: opts.method || 'GET',
      headers: { ...(opts.headers || {}) },
    };
    if (body) ro.headers['Content-Length'] = Buffer.byteLength(body);
    const req = lib.request(ro, res => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const buf = Buffer.concat(chunks);
        resolve({
          ok: res.statusCode >= 200 && res.statusCode < 300,
          status: res.statusCode,
          text: () => Promise.resolve(buf.toString()),
          json: () => Promise.resolve(JSON.parse(buf.toString())),
          arrayBuffer: () => Promise.resolve(buf.buffer.slice(buf.byteOffset, buf.byteOffset + buf.byteLength)),
        });
      });
    });
    req.on('error', reject);
    if (body) req.write(body);
    req.end();
  });
