// Config
const FISH_API_KEY = '145c958d4b194854b82e045f103472ee';
const REFERENCE_ID = '9d84b9dd0a11472a99d0a16915bbc622';
const MODEL = 's1';
const MAX_RETRIES = 1;
const RETRY_DELAY_MS = 5000;

// ─── retry helper ───
async function withRetry(fn, label = 'API call') {
  for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
    try {
      return await fn();
    } catch (err) {
      if (attempt === MAX_RETRIES) throw err;
      await new Promise(r => setTimeout(r, RETRY_DELAY_MS));
    }
  }
}

const production = $('Prepare Production').first().json;
const chatId = production.chatId;
const copyJson = production.copyJson;

// ─── Build VO text from copy JSON ───
// Copy JSON has: hookVO, bodyClips[].vo, outroVO
// We concatenate all VO lines with pauses between them

if (!copyJson) {
  // Self-healing: no copy data → continue without VO
  return [{
    json: {
      success: true,
      voSkipped: true,
      chatId,
      scenarioName: production.scenarioName,
      warning: '\u26A0\uFE0F No copy JSON found in scenario (generated_copy_json field missing). Continuing without voiceover.',
    }
  }];
}

const voLines = [];
if (copyJson.hookVO) voLines.push(copyJson.hookVO);
if (Array.isArray(copyJson.bodyClips)) {
  for (const clip of copyJson.bodyClips) {
    if (clip.vo) voLines.push(clip.vo);
  }
