}

// Specific scenario
return [{
  json: {
    scenarioName,
    chatId,
    scenarioFilter: 'AND({scenario_name} = "' + scenarioName + '", {status} = "ready")',
  }
}];

// NODE: Prepare Production (MVP — Concept 3: chat_screenshot)
// Consolidates scenario data + body clips into a production plan
// Mode: Run Once for All Items
//
// WIRING: Find Produce Clips (Airtable) → this Code node → Generate Hook
// References: $('Load Production Data'), $('Find Produce Scenario'), $input (body clips)

// Helper: "toxic-sad-happy-girl-1771197483216" → "Toxic Sad Happy Girl"
function formatName(raw) {
  if (!raw) return 'Scenario';
  return raw.replace(/-\d{10,}$/, '').split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
}

const chatId = $('Load Production Data').first().json.chatId;

// ─── Get scenario from Airtable search result ───
const scenarioItems = $('Find Produce Scenario').all().map(i => i.json);
if (scenarioItems.length === 0) {
  return [{
    json: {
      error: true,
      chatId,
      message: '⚠️ Nessuno scenario pronto (status=ready) trovato.',
    }
  }];
}

const scenario = scenarioItems[0];
const scenarioName = scenario.scenario_name;

// ─── Parse scenario JSON ───
let scenarioJson = scenario.scenario_json;
if (typeof scenarioJson === 'string') {
  try { scenarioJson = JSON.parse(scenarioJson); } catch(e) { scenarioJson = null; }
}

// ─── Parse copy JSON (contains VO scripts) ───
let copyJson = scenario.generated_copy_json;
if (typeof copyJson === 'string') {
  try { copyJson = JSON.parse(copyJson); } catch(e) { copyJson = null; }
}

// ─── Get body clips from input (Airtable search result) ───
const clipRecords = $input.all().map(i => i.json);

if (clipRecords.length === 0) {
  return [{
    json: {
      error: true,
      chatId,
      message: '⚠️ Nessuna body clip trovata per "' + formatName(scenarioName) + '". Registra prima le clip.',
    }
  }];
}

// ─── Hook type: chat_screenshot for Concept 3 MVP ───
const hookType = 'chat_screenshot';

// ─── Outro: skip for Concept 3 ───
const selectedOutro = { type: 'none' };

// ─── Standard body clip template ───
const template = {
  segments: [
    { section: 'hook', duration: 3.0 },
    { section: 'screenshot', duration: 1.0 },
    { section: 'upload_chat', duration: 1.0 },
    { section: 'toxic_score', duration: 3.0 },
    { section: 'soul_type', duration: 3.0 },
    { section: 'deep_dive', duration: 3.0 },
  ],
  totalDuration: 14.0,
};

// ─── Sort and map body clips ───
const bodyClips = clipRecords
  .filter(c => c.clip_type === 'body' || !c.clip_type)
  .sort((a, b) => (a.clip_index || 0) - (b.clip_index || 0))
  .map(clip => ({
    clipIndex: clip.clip_index,
    section: clip.section || 'body_' + clip.clip_index,
    fileId: clip.telegram_file_id,
    duration: clip.clip_duration_sec || 0,
    clipName: clip.clip_name,
  }));

// ─── Map clips to template body segments ───
const bodySegments = template.segments.filter(s => s.section !== 'hook' && s.section !== 'outro');
const clipMapping = bodySegments.map((seg, i) => {
  let clip = bodyClips.find(c => c.section === seg.section);
  if (!clip && i < bodyClips.length) clip = bodyClips[i];
  return {
    section: seg.section,
    targetDuration: seg.duration,
    fileId: clip ? clip.fileId : null,
    actualDuration: clip ? clip.duration : null,
  };
});

return [{
  json: {
    scenarioName,
    displayName: formatName(scenarioName),
    chatId,
    hookType,
    selectedOutro,
    scenarioJson,
    copyJson,
    template,
    bodyClips,
    clipMapping,
    scenarioRecordId: scenario.id,
    hookText: scenario.generated_hook_text || '',
  }
}];
